sp_widget.client_script:
api.controller=function($scope, spModal, $rootScope, spUtil) {
	// STRY0079658 removed dtBreadcrumbs since this is always used in a a page by itself or in modal
	var c = this;
	$scope.submitting = false;
	var g_form;
	if (c.data.currentStep == undefined){
		c.data.currentStep = 'selectTemplate';
	}
	// NOTE:  I could use a different click here.  I could use data table without tasker data table
	// ISSUE: the Tasker DataTable, if you go to the 
	$scope.$on("data_table.click", function(evt, e) {
		c.data.selected_Template_id = e.sys_id;
  });
	c.changeTemplateLevel = function() {
		var o="";
		var d="";
		var table = "x_153465_discovert_discover_routing_template";
		var filter = "";
		var view = "";
		var title = "";
		switch (c.data.templateLevel) {
			case "all":
				title = "Any";
				filter = c.data.allFilter;
				view = "OUProcess";
				break;
			case "global":
				title = "a Global";
				filter = c.data.globalFilter;
				view = "GlobalProcess";			
				break;
			case "organizationalunit":
				title = "an OU";
				// TODO, LOOK UP THE OUs FOR THIS USER
				filter = c.data.ouFilter;
				view = "OUProcess";
				break;
			case "personal":
				title = "a Personal";
				filter = c.data.myFilter;
				view = "myprocess";			
				break;
			default:
				filter = "";
		}

		var params = {
			o: o,
			d: d,
			table: table,
			filter: filter,
			view: view, 
			title: "Select " + title + " Template to Start",
			open_row_details_in_modal: false,
			window_size : "10"
		};
		spUtil.get('discovertasker-widget-data-table',params).then(function(response){
			c.data.templateListWidget = response;
		});	
	};

	$scope.btnCancelClick = function() {
		// close modal window
		$scope.$parent.buttonClicked($scope.$parent.options.buttons[0]);
	};

	$scope.btnBackClick = function() {
		// go back to selection page
		c.data.selected_Template_id = '';
		c.data.currentStep = 'selectTemplate';
		c.changeTemplateLevel();
	};

	$scope.btnNextButton = function() {
		if(c.data.selected_Template_id=='' || c.data.selected_Template_id== undefined){
			alert('Please select the Template to run.');
		} else{
			c.data.currentStep = 'enterInfo';
			c.server.update();
		}
	};

	// STRY0123152
	$scope.btnGenderateDraftButton = function() {
		startTemplate('generate_draft');
	};

	$scope.btnStartButton = function() {
		startTemplate('start_template');
	};

	function startTemplate(action) {
			if(g_form){
				$scope.submitting = true;
				if(g_form.submit(action)){
					$(".showAlert").hide().show('medium');
					c.data.currentStep = 'StartTemplate';
				}
				$scope.submitting = false;
			}
	}


	// STRY0100724: DEV Story- Performance Improvements -  Running Templates and implify
	function initForm(gFormInstance) {
		if (gFormInstance.getTableName() != undefined &&
				gFormInstance.getTableName() == $scope.data.f.table) {
			g_form = gFormInstance;
		}
	}

	$scope.$on('spModel.gForm.env.created', function(e, gFormInstance) {
		initForm(gFormInstance);
	});

};

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES 
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 09.09.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------


.iconlink a label,h2 {
  display: block;
  font-size: 1em;
  font-weight: 300;
  line-height: 1.1;
  padding: 0;
  margin: 0 0 10px 0;
  cursor: pointer;
}



//------------------------------------------------------------------------------------------------------------------------
// CUSTOM
//------------------------------------------------------------------------------------------------------------------------


/* SECTIONS & FORMS */
//------------------------------------------------------------------------------------------------------------------------
.ng-isolate-scope .h4.ng-binding{
  font-weight: 400 !important;
  font-family: "SourceSansPro", Helvetica, Arial, sans-serif; //'Lucida Sans Unicode';
  padding-left: 5px;
	border-left-style: solid;
	border-left-color: $primary;
	border-left-width: 5px;
	color: $primary;
	padding-top: 8px;
	padding-bottom: 5px;
}

fieldset.ng-scope{
  margin-top: 5px;
}

label{
	//font-weight: 100!important;
  color: $primary;
}


/* DURATION */
//------------------------------------------------------------------------------------------------------------------------

#dur-minutes,
#dur-seconds { 
  visibility: hidden!important;
}

#dur-days,
#dur-hours { 
  width: 40px!important
}


//------------------------------------------------------------------------------------------------------------------------
// OOTB FORM WIDGET
//------------------------------------------------------------------------------------------------------------------------


.btn-form-menu {
	vertical-align: inherit;
  padding: inherit;
  background: none;
}

.panel-title {
  word-wrap: break-word;
}

.panel-heading {
  .dropdown-menu {
    a {
      white-space: normal;
    }
  }
}

.comment {
	font-weight: bold;
	margin-top: 2px;
	margin-bottom: 2px;
}
.mce-panel, .mce-btn {
	background-image: none;
	background-color: #f0f3f4;
}

.action-btn {
  margin-right: 5px;
}

.comment {
   max-height: 50vh;
   height: 100%;
   overflow-y: auto;
}

.panel .panel {
    height: auto !important;
}

.attachment-button {
  .glyphicon-paperclip {
    font-size: 18px;
  }
}

.dropdown {
  .glyphicon-menu-hamburger:focus {
 		outline: thin dotted;
		outline: 5px auto $input-border-focus;
		outline-offset: -2px; 
	}
}

.text-success-alt {
	background-color: $state-success-text;
}

.text-info-alt {
	background-color: $state-info-text;
}

