// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// WIDGET BASE: TASKER DATA TABLE
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: Rob Joy
//------------------------------------------------------------------------------------------------------------------------
//
// 2.7.0 | 07.05.2021 | raj | STRY0100724: DEV Story- Performance Improvements -  Running Templates and implify
//                                   Updates in Server, Client and HTML
// 2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
// 											In CSS, selector .taskform-classification-banner removed, not used. 
// 											 Selector .assignmentgroup-banner removed, not used.
//											 Selector #sp_formfield_status removed, was commented out.
//											In Server script, fixed white space issues, format whole script.
//                                          Changes in CSS and Server script
// 2.7.0 | 2021-10-29 | mmcc | STRY0110472 - Stretch- 508 Compliant- Delete Buttons- (ALL Red buttons) 
//											In CSS, Comment out unused .sc-field-error-label.
//                                          Changes in CSS
// 2.7.0 | 2021-10-230 | raj | STRY0113375 - Draft from Templates Update- UI- Add "Draft Template" Action Button
//											In HTML,updated button text and hover
//											NOTE: caption and hover should pick up from UI Actions, but don't
// 2.8.0 | 2022-06-02 | raj | STRY0123152 - Draft Tasks- Selecting "Run Template" from 'Draft Tasks' only generates 'Drafts Tasks'
//											Changes in Server Script, Client Controller and HTML
// 2.8.0 | 2022-08-13 | raj  | STRY0126024 - Templates- Add Classification/Restricted Group Ribbons on Template Forms
//																			Changes in Server Script and HTML
// 2.8.1 | 2022-12-09 | mmcc | STRY0133733 - 2.8.1 Tech Debt - Update Tasker App to set CSS Style for Classification based on Value
//                                      In HTML, for top Ribbon changed taskform-classification-banner- to use {{data.classificationValue}}
//                                      In Server script, added data.classificationValue set with ._fields.classification.value
//                                      Changes made in HTML and Server script.
// 2.8.1 | 2022-12-13 | mmcc | DFCT0011322 -  Click on the "Select Template to Start" form, "General Information", section header should NOT 
//                                         display on top of the "Classification" ribbon 
//                                      In HTML, After Ribbon add CSS Selector dtech top padding 15px to sp-modal tag
//                                      In Client controller, added api.controller= and semicolon to right curly bracket and 
//                                       removed angular.element call
//                                      Changes made in HTML and Client controller.
// 2.8.1 | 2023-03-15 | mmcc | STRY0136499 - Tech Debt (Release 2.8.1) - Update Tasker App to set CSS Style for Classification based on Value
//                                      In HTML, in Ribbon section updated to use data.f._fields.classification.displayValue;
//                                      In Server script, removed if (data.f._fields.classification) {}
//                                      Changes made in HTML and Server script.
// 2.8.1 | 2023-05-17 | mmcc | DFCT0011852 - Click on any banner notification > right side empty state
//                should stretch to fill area to match the standard layout for flexing header-body-footer
//                                      In CSS, delete comment block for STRY0110472; delete unused .empty-state-wrapper block
//                                      Changes made in CSS.
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp) {
    // STRY0079658 added $sp to get the parentTask off of the URL on mobile
    /* populate the 'data' object */
    /* e.g., data.table = $sp.getValue('table'); */
    data.templateLevel = (input || {}).templateLevel || 'all';
    data.parentTask = (input || {}).parentTask || (options || {}).parentTask || $sp.getParameter('parentTask');
    // STRY0100724
    data.selected_Template_id = (input || {}).selected_Template_id || (options || {}).selected_Template_id || $sp.getParameter('selected_Template_id');
    // STRY0098385 - remove Cancel button from Mobile 
    data.page_id = $sp.getParameter("id");

    var widgetParams = {};
    var taskingScripts = new tasking_System_Settings_Scripts();
    // STRY0079658 added parent task to get restricted group
    var templateFilters = taskingScripts.getTemplateFilters(true, data.parentTask);

    data.userHasPersonalTemplateRights = templateFilters.hasMyTemplateRights + '';
    // if the user has personal template permissions, they can run personal templates
    data.userHasOUTemplateRights = templateFilters.hasOUTemplateRights + '';
    // if user is a Task Administrator, they can run Global Templates
    data.userHasGlobalTemplateRights = templateFilters.hasGlobalTemplateRights + '';
    data.allFilter = templateFilters.allTemplateFilter;
    data.myFilter = templateFilters.myTemplateFilter;
    data.ouFilter = templateFilters.ouFilter;
    data.globalFilter = templateFilters.globalFilter;
    data.f = {};

		// STRY0123152
		if(data.parentTask){
			var gr_Parent = new GlideRecord("x_153465_discovert_route_task_instance");
			if(gr_Parent.get(data.parentTask)){
				if(gr_Parent.state==-6){
					data.draftOnly = true;
				}
			}
		}

    // initial load, build the original data table widget
    // STRY0097161
    if (input == undefined || input.currentStep == undefined) {
        var table = "x_153465_discovert_discover_routing_template";
        var filter = "";
        var view = "OUProcess";
        var o = "";
        var d = "";
        widgetParams = {
            o: o,
            d: d,
            table: table,
            filter: data.allFilter,
            view: view,
            title: "Select Template to Start",
            open_row_details_in_modal: false,
            window_size: 10
        };
        data.widgetParams = widgetParams;
		data.templateListWidget = $sp.getWidget('discovertasker-widget-data-table', widgetParams);
	} else if (input.currentStep == 'enterInfo') {
		data.canAttach = false;
		// build the Template Instance Form here
		data.f = $sp.getForm("x_153465_discovert_discover_routing_runtime", "-1", 'parent_task=' + data.parentTask + 
					'^routing_template_ref=' + data.selected_Template_id, "Default View");

		if(data.f._fields.u_restricted_group){
			data.restrictedGroup = data.f._fields.u_restricted_group.displayValue;
		}
		data.canRun = new uiConditionCheck().startTemplateUIAction(data.selected_Template_id, data.parentTask);
	}
})($sp);
